UPDATE design_objects do_
SET metadata = jsonb_set(metadata, '{sidecar}', sc.sidecar, true)
FROM shape_sidecars sc
WHERE do_.type IN ('shape', 'shape_part')
  AND do_.metadata->>'source' = 'library'
  AND do_.metadata->>'shape_id' = sc.shape_id
  AND NOT (do_.metadata ? 'sidecar');